/**
 * @param {number} n
 * @param {number[][]} edges
 * @return {number}
 */
function solve(n, edges) {
    // This problem is about maintaining a set of edges such that every cycle has an even total weight.
    // This property is equivalent to saying that the graph is bipartite in terms of parity,
    // or more precisely, that the XOR sum of edge weights along any cycle is 0.
    // If we consider the weights modulo 2 (i.e., 0 or 1), the condition is that the cycle basis must have XOR sum 0.
    // This is equivalent to maintaining connected components where the distance parity (or potential) between any two nodes in the same component is fixed.

    // We can use a Disjoint Set Union (DSU) structure, augmented to track the parity of the path from a node to the representative of its set.
    // Let dist[i] be the parity of the path weight from node i to its current parent in the DSU tree.

    const parent = Array(n).fill(0).map((_, i) => i);
    // parity[i] stores the XOR sum of edge weights on the path from i to parent[i].
    const parity = Array(n).fill(0); 

    /**
     * Finds the representative (root) of the set containing i, performing path compression
     * and updating the parity along the path.
     * @param {number} i
     * @returns {number} The root of the set.
     */
    function find(i) {
        if (parent[i] === i) {
            return i;
        }
        // Recursive call to find the root and update the parent's parity
        const root = find(parent[i]);

        // Update the parity of i:
        // new_parity[i] = parity[i] (i -> old_parent) XOR parity[old_parent] (old_parent -> root)
        parity[i] = parity[i] ^ parity[parent[i]];

        parent[i] = root;
        return root;
    }

    /**
     * Unites the sets containing u and v, adding the edge (u, v) with weight w.
     * Returns true if the edge is added successfully (does not create an odd cycle), false otherwise.
     * @param {number} u
     * @param {number} v
     * @param {number} w The weight (0 or 1).
     * @returns {boolean} True if the edge is added, false otherwise.
     */
    function union(u, v, w) {
        const rootU = find(u);
        const rootV = find(v);

        if (rootU !== rootV) {
            // The nodes are in different components. We can add the edge without creating a cycle.
            // Merge V's set into U's set (arbitrarily).
            parent[rootV] = rootU;

            // We need to set parity[rootV] such that the path from rootV to rootU has the correct parity.
            // We know:
            // 1. Path (u -> rootU) has parity: parity[u]
            // 2. Path (v -> rootV) has parity: parity[v]
            // 3. New edge (u -> v) has weight: w
            // We want: Path (rootV -> rootU) = Path (rootV -> v) XOR (v -> u) XOR (u -> rootU)
            // Path (rootV -> v) has parity: parity[v] (since parity[v] is v -> rootV, the reverse is same)
            // Path (v -> u) has parity: w
            // Path (u -> rootU) has parity: parity[u]

            // The path from rootV to rootU must be: rootV -> v --w--> u -> rootU
            // Parity(rootV -> rootU) = Parity(rootV -> v) ^ w ^ Parity(u -> rootU)
            // Parity(rootV -> v) = parity[v] (since path in DSU is from node to root)
            // Parity(u -> rootU) = parity[u]
            // So, parity[rootV] = parity[v] ^ w ^ parity[u]

            parity[rootV] = parity[v] ^ w ^ parity[u];
            return true;
        } else {
            // The nodes are already in the same component. Adding the edge creates a cycle.
            // The existing path between u and v in the current structure has parity:
            // Parity(u -> rootU) XOR Parity(v -> rootU) = parity[u] XOR parity[v]

            // The new cycle is formed by: u --w--> v --(existing path)--> u
            // The total cycle weight parity is: w XOR (parity[u] XOR parity[v]).

            // If this total parity is 0 (even), the edge is safe to add.
            // If this total parity is 1 (odd), the edge must be rejected.
            const cycleParity = w ^ parity[u] ^ parity[v];

            return cycleParity === 0;
        }
    }

    let addedEdgesCount = 0;

    for (const edge of edges) {
        const [u, v, w] = edge;

        const rootU = find(u);
        const rootV = find(v);

        if (rootU !== rootV) {
            // Case 1: Not in the same component. Always add.
            // Perform union and update parity.
            parent[rootV] = rootU;
            // parity[rootV] = parity[v] ^ w ^ parity[u] (using the logic derived for union)
            parity[rootV] = parity[v] ^ w ^ parity[u];
            addedEdgesCount++;
        } else {
            // Case 2: In the same component. Check for odd cycle.
            // Cycle parity = w XOR parity[u] XOR parity[v]
            const cycleParity = w ^ parity[u] ^ parity[v];

            if (cycleParity === 0) {
                // Even cycle, add the edge.
                addedEdgesCount++;

                // If we add the edge (u, v) with weight w, and it closes an even cycle, 
                // we must update the parity structure to reflect this new valid path.
                // Since rootU == rootV, the path from u to v via the new edge has parity w.
                // The path from u to v via the tree currently has parity parity[u] ^ parity[v].
                // We need to maintain the invariant: Parity(u -> rootU) = parity[u].
                // If we add (u, v), the new path u -> v has weight w.
                // The tree path u -> v has weight parity[u] ^ parity[v].
                // Since w ^ (parity[u] ^ parity[v]) = 0, we have w = parity[u] ^ parity[v].
                // The edge is consistent with the existing structure regarding parity. No structural update is needed for DSU, 
                // as the invariant holds for all nodes.
                // If the cycle parity is 0, the structure remains valid.
            }
            // If cycleParity is 1, we discard the edge.
        }
    }

    return addedEdgesCount;
}

