struct Dsu {
    parent: Vec<usize>,
    // parity[i] stores the XOR sum of edge weights on the path from i to parent[i].
    parity: Vec<i32>,
}

impl Dsu {
    fn new(n: usize) -> Self {
        Dsu {
            parent: (0..n).collect(),
            parity: vec![0; n],
        }
    }

    // Finds the representative (root) of the set containing i, performing path compression
    // and updating the parity along the path.
    // Returns (root, parity_to_root)
    fn find(&mut self, i: usize) -> (usize, i32) {
        if self.parent[i] == i {
            return (i, 0);
        }

        // Recursive call to find the root and get the parity from parent[i] to root
        let (root, parent_to_root_parity) = self.find(self.parent[i]);

        // Update the parity of i:
        // new_parity[i] = parity[i] (i -> old_parent) XOR parent_to_root_parity (old_parent -> root)
        self.parity[i] ^= parent_to_root_parity;

        // Path compression
        self.parent[i] = root;

        (root, self.parity[i])
    }

    // Attempts to unite the sets containing u and v, adding the edge (u, v) with weight w.
    // Returns true if the edge is added successfully (does not create an odd cycle), false otherwise.
    fn union_and_check(&mut self, u: usize, v: usize, w: i32) -> bool {
        let (root_u, parity_u) = self.find(u);
        let (root_v, parity_v) = self.find(v);

        if root_u != root_v {
            // Case 1: Not in the same component. Always add.

            // Merge V's set into U's set (arbitrarily).
            self.parent[root_v] = root_u;

            // Set parity[root_v] such that the path from root_v to root_u has the correct parity.
            // Path: root_v --(new)--> v --w--> u --(tree)--> root_u
            // Parity(root_v -> root_u) = Parity(root_v -> v) XOR w XOR Parity(u -> root_u)
            // Parity(root_v -> v) = parity_v (since path in DSU is node to root, reverse is same)
            // Parity(u -> root_u) = parity_u
            // So, parity[root_v] = parity_v ^ w ^ parity_u
            self.parity[root_v] = parity_v ^ w ^ parity_u;

            true
        } else {
            // Case 2: In the same component. Check for odd cycle.

            // The existing path between u and v in the current structure has parity:
            // Parity(u -> root_u) XOR Parity(v -> root_u) = parity_u XOR parity_v

            // The new cycle is formed by: u --w--> v --(existing path)--> u
            // The total cycle weight parity is: w XOR (parity_u XOR parity_v).
            let cycle_parity = w ^ parity_u ^ parity_v;

            // We add the edge if the cycle parity is 0 (even cycle).
            cycle_parity == 0
        }
    }
}

fn solve(n: i64, edges: Vec<Vec<i64>>) -> i64 {
    let n_usize = n as usize;
    let mut dsu = Dsu::new(n_usize);
    let mut added_edges_count = 0;

    for edge in edges {
        let u = edge[0] as usize;
        let v = edge[1] as usize;
        let w = edge[2] as i32; // w is 0 or 1

        if dsu.union_and_check(u, v, w) {
            added_edges_count += 1;
        }
    }

    added_edges_count
}
