impl DSU {
    fn new(n: usize) -> DSU {
        DSU {
            parent: (0..n).collect(),
            parity: vec![0; n],
        }
    }

    // Finds the representative (root) of the set containing i, performing path compression
    // and updating the parity along the path.
    // Returns (root, parity_to_root)
    fn find(&mut self, i: usize) -> (usize, i64) {
        if self.parent[i] == i {
            return (i, 0);
        }

        // Recursive call to find the root and update the parity along the path
        let (root, parity_to_root_of_parent) = self.find(self.parent[i]);

        // Update the parity of i:
        // new_parity[i] = parity[i] (i -> old_parent) XOR parity_to_root_of_parent (old_parent -> root)
        self.parity[i] ^= parity_to_root_of_parent;

        self.parent[i] = root;

        (root, self.parity[i])
    }

    // Attempts to unite sets containing u and v with edge weight w.
    // Returns true if the edge is added successfully (does not create an odd cycle), false otherwise.
    fn union(&mut self, u: usize, v: usize, w: i64) -> bool {
        let (root_u, parity_u) = self.find(u);
        let (root_v, parity_v) = self.find(v);

        if root_u != root_v {
            // The nodes are in different components. We can add the edge without creating a cycle.
